import{_ as e,c as a,a as n,o as i}from"./app-CEcM0piI.js";const l={};function t(p,s){return i(),a("div",null,s[0]||(s[0]=[n(`<p>react中hook函数的使用规则：</p><ol><li>只能在组件中或者其他自定义Hook函数中调用</li><li>只能在组件的顶层调用，不能嵌套在if、for、其他函数中</li></ol><p><mark>hook函数只能在函数式组件中使用</mark></p><h2 id="usestate" tabindex="-1"><a class="header-anchor" href="#usestate"><span>useState</span></a></h2><p>useState是一个React Hoot函数，它允许我们返回一个状态变量，状态变量一旦发生变化组件的视图UI也会跟着变化（数据驱动视图） 类似于vue的ref</p><p>使用useState绑定一个变量会返回一个对象，这个对象包含对该变量的setter和getter（本身）</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const [count,setCount]=useState(0)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="useref" tabindex="-1"><a class="header-anchor" href="#useref"><span>useRef</span></a></h2><p>使用useRef创建ref对象并与jsx绑定dom 类似vue的ref</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const inputRef=useRef(null)</span></span>
<span class="line"><span>&lt;input type=&quot;text ref={inputRef} /&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="useeffect" tabindex="-1"><a class="header-anchor" href="#useeffect"><span>useEffect</span></a></h2><p>用于在React组件中创建不是由事件引起而是由渲染本身引起的操作，比如发送AJAX请求，更改DOM等等</p><p>相当于vue的watchEffect，但vue的不会在开始就触发，而useEffect会在开始时触发一次</p><table><thead><tr><th>依赖项</th><th>副作用函数执行时机</th></tr></thead><tbody><tr><td>没有依赖项</td><td>组件初始渲染+组件更新时执行</td></tr><tr><td>空数组</td><td>依赖只在初始渲染时执行一次</td></tr><tr><td>添加特定依赖项</td><td>组件初始渲染+特性依赖项变化时执行</td></tr></tbody></table><ul><li>参数1：是一个函数，可以把它叫做副作用函数，在函数内部可以放置要执行的操作</li><li>参数2：是一个数组（可选参），在数组里放置依赖项，不同依赖项会影响第一个参数函数的执行，当是一个空数组的时候，副作用函数只会在组件染完毕之后执行一次</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function App (){</span></span>
<span class="line"><span>	useEffect(()=&gt;{</span></span>
<span class="line"><span>		const list=await axios.get(&#39;localhost:3000/user&#39;)</span></span>
<span class="line"><span>		console.log(list)</span></span>
<span class="line"><span>	},[])</span></span>
<span class="line"><span>	return(</span></span>
<span class="line"><span>		&lt;div&gt;</span></span>
<span class="line"><span>		&lt;/div&gt;</span></span>
<span class="line"><span>	)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="清除副作用" tabindex="-1"><a class="header-anchor" href="#清除副作用"><span>清除副作用</span></a></h4><p>在useEffect中编写的由渲染本身引起的对接组件外部的操作，社区也经常把它叫做副作用操作，比如在useEffect中开启了一个定时器，我们想在组件卸载时把这个定时器再清理掉，这个过程就是清理副作用</p><p>清除副作用的函数最常见的执行时机时在组件卸载时自动执行</p><p>在useEffect的第一个函数参数的返回函数中定义清除副作用逻辑</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>useEffect(()=&gt;{</span></span>
<span class="line"><span>	// 实现副作用操作逻辑</span></span>
<span class="line"><span>	return ()=&gt;{</span></span>
<span class="line"><span>		// 清除副作用逻辑</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="usememo" tabindex="-1"><a class="header-anchor" href="#usememo"><span>useMemo</span></a></h2><p>让一段计算在开始运行一次，后续只有依赖的数据发生变化时才重新运算 作用：</p><ol><li>起类似于vue的一个计算属性的效果</li><li>缓存一个数据，让其不会重新创建。</li></ol><h2 id="usecallback" tabindex="-1"><a class="header-anchor" href="#usecallback"><span>useCallback</span></a></h2><p>缓存一个函数，每次组件刷新时不会重复创建</p><p>useEffect、useMemo、useCallback的第二个参数依赖列表作用都是一样的</p><h2 id="usecontext" tabindex="-1"><a class="header-anchor" href="#usecontext"><span>useContext</span></a></h2><p>useContext并不能创建context，它只是更简便地使用context，创建context依旧需要createContext</p><h2 id="自定义hook函数" tabindex="-1"><a class="header-anchor" href="#自定义hook函数"><span>自定义hook函数</span></a></h2><p>hook函数就是use开头的一系列函数，用户也可以自己封装重复的逻辑为一个hook函数 类似于vue的自定义指令，但react中更贴近于自己封装函数</p><p>原本实现一个按钮点击控制</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function App(){</span></span>
<span class="line"><span>	const [value,setValue]=useState(true)</span></span>
<span class="line"><span>	const toogle=()=&gt; setValue(!value)</span></span>
<span class="line"><span>	return(</span></span>
<span class="line"><span>		&lt;button onClick={toggle}&gt;{value &amp;&amp; toggle}&lt;/button&gt;</span></span>
<span class="line"><span>	)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>封装自定义的toogle</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function useToogle(){</span></span>
<span class="line"><span>	const [value,setValue]=useState(true)</span></span>
<span class="line"><span>	const toogle=()=&gt; setValue(!value)</span></span>
<span class="line"><span>	return(</span></span>
<span class="line"><span>		value,</span></span>
<span class="line"><span>		toggle</span></span>
<span class="line"><span>	)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>function App(){</span></span>
<span class="line"><span>	const [value,toogle]=useToggle()</span></span>
<span class="line"><span>	return(</span></span>
<span class="line"><span>		&lt;button onClick={toggle}&gt;{value &amp;&amp; toggle}&lt;/button&gt;</span></span>
<span class="line"><span>	)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h2 id="高阶组件" tabindex="-1"><a class="header-anchor" href="#高阶组件"><span>高阶组件</span></a></h2><p>类似于vue中的mixin当我们发现某个操作逻辑，或者某个运算经常出现的时候，我们可以提取为高阶组件</p><ul><li>组件：既包含了ui界面的复用，也包含了逻辑的复用</li><li>高阶组件：只是复用操作逻辑，，运算</li></ul>`,38)]))}const c=e(l,[["render",t]]),r=JSON.parse('{"path":"/front/react/3/","title":"3 React18","lang":"zh-CN","frontmatter":{"title":"3 React18","createTime":"2025/06/01 18:18:18","permalink":"/front/react/3/"},"readingTime":{"minutes":3.17,"words":952},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/React/3 React18.md","headers":[]}');export{c as comp,r as data};
